logger = logging.getLogger(__name__)


device = torch.device("cuda" if torch.cuda.is_available() else "cpu")

def save_to_parquet(
    data: List[Dict], 
    filepath: str, 
    compression: str = 'snappy'
    ) -> None:
    
    df = pd.DataFrame(data)
    df.to_parquet(filepath, compression=compression, index=False)
    print(f"✅ Сохранено {len(df)} записей в {filepath}")

def load_parquet(filepath: str) -> pd.DataFrame:
    if not Path(filepath).exists():
        raise FileNotFoundError(f"Файл не найден: {filepath}")
    
    df = pd.read_parquet(filepath)
    print(f"Загружено {len(df)} записей из {filepath}")
    return df


def load_from_parquet(
    queries_path: str, 
    qrels_path: str
    ) -> Tuple[Dict[str, str], Dict[str, Dict[str, int]]]:
    
    df_queries = pd.read_parquet(queries_path)
    queries = dict(zip(df_queries['query_id'].astype(str), df_queries['query_text'].astype(str)))
    
    df_qrels = pd.read_parquet(qrels_path)
    
    qrels = dict()
    for _, row in df_qrels.iterrows():
        q_id = str(row['query_id'])
        d_id = str(row['doc_id'])
        label = int(row['label'])
        
        if q_id not in qrels:
            qrels[q_id] = dict()
        
        qrels[q_id][d_id] = label
    
    return queries, qrels



def unboxing(taskname:str):
    queries_dataset = load_parquet(f"{taskname}-queries.parquet")
    corpus_dataset = load_parquet(f"{taskname}-corpus.parquet")
    qrels_dataset = pd.concat([load_parquet(f"{taskname}-qrels1.parquet"), load_parquet(f"{taskname}-qrels2.parquet")])
    
    queries = dict()
    for _, row in queries_dataset.iterrows():
        q_id = str(row["_id"])
        q_text = str(row["text"])
        queries[q_id] = q_text

    corpus = dict()
    for _, row in corpus_dataset.iterrows():
        q_id = str(row["_id"])
        q_title = str(row["title"])
        q_text = str(row["text"])
        if q_id not in corpus:
            corpus[q_id] = dict()
        corpus[q_id]["text"] = q_text
        corpus[q_id]["title"] = q_title

    qrels = dict()
    for _, row in qrels_dataset.iterrows():
        q_id = str(row["query-id"])
        c_id = str(row["corpus-id"])
        score = int(row["score"])
        if q_id not in qrels:
            qrels[q_id] = dict()
        
        qrels[q_id][c_id] = score

    return  corpus, queries, qrels




    

    


def ask_server(query, llmname, prompt, key, width):
    client = Groq(api_key=key)

    system_instruction = (
        "You must return a valid JSON object with a key 'variants'. "
        "The value must be an array of EXACTLY {width} STRINGS. "
        "Do NOT use objects, dictionaries, or nested structures inside the array. "
        "Each item in the array must be a plain string."
    ).format(width=width)

    example_output = (
        "Example of correct format:\n"
        '{"variants": ["string variant 1", "string variant 2", "string variant 3"]}'
    )

    chat_completion = client.chat.completions.create(
        messages=[
            {
                "role": "system",
                "content": system_instruction
            },
            {
                "role": "user",
                "content": f"{prompt}: {query}\n\n{example_output}",
            }
        ],
        max_completion_tokens=300, 
        response_format={
            "type": "json_schema",
            "json_schema": {
                "name": "variants_schema",
                "strict": False,
                "schema": {
                    "type": "object",
                    "properties": {
                        "variants": {
                            "type": "array",
                            "items": {"type": "string"},  # Требуются строки
                            "minItems": width,
                            "maxItems": width
                        }
                    },
                    "required": ["variants"],
                    "additionalProperties": False
                }
            }
        },
        model=llmname
    )
    
    # 3. Безопасный парсинг
    try:
        content = chat_completion.choices[0].message.content
        result = json.loads(content) if content else {}
        return result.get("variants", [])
    except json.JSONDecodeError as e:
        print(f"JSON Decode Error: {e}")
        print(f"Raw content: {chat_completion.choices[0].message.content}")
        return []



class COIR:
    def __init__(self, tasks, batch_size, type="semantic"):
        self.tasks = tasks
        self.batch_size = batch_size
        self.type = type
        self.llm_init('','')
        #######################################


    def llm_init(self, llmname, prompt, key=''):
        self.llmname = llmname
        self.prompt=prompt
        self.key = key


    def expand_n_save(self, width):
        for task_name, task_data in self.tasks.items():
            corpus, queries, qrels = task_data
            prefixes = [str(i) for i in range(width)]
            new_qrels = {prefix + q: d for q, d in qrels.items() for prefix in prefixes}
            new_queries = dict()
            with tqdm(total=len(queries), desc="Expanding queries", unit="query") as pbar:
                for qid, query in queries.items():
                    nq = ask_server(query, self.llmname, self.prompt, self.key, width)
                    pbar.update(1)
                    for i in range(width):
                        try:
                            new_queries[prefixes[i]+qid] = nq[i] + "\n\n" + query
                        except:
                            new_queries[prefixes[i]+qid] = query
                            print(nq, query)

            new_td = [corpus, new_queries, new_qrels]
            queries_data = [
                {"query_id": q_id, "query_text": q_text} 
                for q_id, q_text in new_queries.items()
            ]
            save_to_parquet(queries_data, f"{self.llmname.replace("/","--")}_{task_name}_queries.parquet")

            qrels_data = [
                {"query_id": q_id, "doc_id": d_id, "label": label}
                for q_id, docs in new_qrels.items()
                for d_id, label in docs.items()
            ]
            save_to_parquet(qrels_data, f"{self.llmname.replace("/","--")}_{task_name}_qrels.parquet")
                


    
    def run(self, model, output_folder: str, useLLm: bool, expanded: bool, local_data:bool = False):
        results = {}
        for task_name, task_data in self.tasks.items():
            corpus, queries, qrels = task_data
            
            if local_data:
                 output_folder = os.path.join(output_folder, f"{task_name}-local/{model.model_name}")
                 corpus, queries, qrels = unboxing(task_name)
                 print(len(corpus), len(queries),len(qrels))
            else:
                output_folder = os.path.join(output_folder, f"{task_name}/{model.model_name}")
            if not useLLm and not expanded:
                output_file = os.path.join(output_folder, f"{self.type}.json")
            elif not useLLm and expanded:
                 output_file = os.path.join(output_folder, f"expanded-by-LLM-{self.llmname.replace("/","-")}_{self.type}.json")
            else:
                output_file = os.path.join(output_folder, f"LLM-{self.llmname.replace("/","-")}_{self.type}.json")

            

           
           
            if expanded:
                query_path = f"{self.llmname.replace("/","--")}_{task_name}_queries.parquet"
                qrels_path = f"{self.llmname.replace("/","--")}_{task_name}_qrels.parquet"
                if not(os.path.exists(query_path) and os.path.exists(qrels_path)):
                    raise FileNotFoundError("not expanded query or qrels")
                
                queries, qrels = load_from_parquet(query_path,qrels_path)

            # Initialize custom model
            custom_model = DRES(model, batch_size=self.batch_size, type=self.type)
            retriever = EvaluateRetrieval(custom_model, score_function="cos_sim")

    
            # Retrieve results
            task_results = retriever.retrieve(corpus, queries, useLLm, self.llmname, self.prompt, key=self.key)


            # Evaluate results
            ndcg, map, recall, precision = retriever.evaluate(qrels, task_results, retriever.k_values)
            metrics = {
                "NDCG": ndcg,
                "MAP": map,
                "Recall": recall,
                "Precision": precision
            }

            
           

            
            os.makedirs(output_folder, exist_ok=True)

            with open(output_file, 'w') as json_file:
                json.dump({"metrics": metrics}, json_file, indent=4)

            logger.info(f"Results for {task_name} saved to {output_folder}")
            results[task_name] = metrics

        return results